1	#pragma once
2	
3	#include "hybrid/abstract_command.hpp"
4	#include "hybrid/dmi_poll.hpp"
5	#include "hybrid/program_buffer.hpp"
6	#include "hybrid/state_abi.h"
7	
8	#include <array>
9	#include <cstdint>
10	#include <stdexcept>
11	
12	namespace hybrid {
13	
14	struct DmiBus
15	{
16	  virtual ~DmiBus() = default;
17	  virtual void write(uint8_t reg, uint32_t value) = 0;
18	  virtual auto read(uint8_t reg) -> uint32_t = 0;
19	};
20	
21	class ResumeDriver
22	{
23	public:
24	  static constexpr uint8_t kData0      = 0x04;
25	  static constexpr uint8_t kData1      = 0x05;
26	  static constexpr uint8_t kDmcontrol  = 0x10;
27	  static constexpr uint8_t kDmstatus   = 0x11;
28	  static constexpr uint8_t kAbstractcs = 0x16;
29	  static constexpr uint8_t kCommand    = 0x17;
30	
31	  static constexpr uint16_t kCsrDpc      = 0x7B1;
32	  static constexpr uint16_t kCsrMstatus  = 0x300;
33	  static constexpr uint16_t kCsrMtvec    = 0x305;
34	  static constexpr uint16_t kCsrVstart   = 0x008;
35	  static constexpr uint16_t kCsrVxsat    = 0x009;
36	  static constexpr uint16_t kCsrVxrm     = 0x00A;
37	  static constexpr uint16_t kCsrVcsr     = 0x00F;
38	  static constexpr uint16_t kCsrVtype    = 0xC21;
39	  static constexpr uint16_t kCsrVl       = 0xC20;
40	
41	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
42	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
43	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
44	
45	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
46	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
47	
48	  static constexpr uint32_t kAbstractcsBusy        = 1u << 12;
49	  static constexpr uint32_t kAbstractcsCmderrMask  = 0x7u << 8;
50	
51	  static constexpr unsigned kPollIterations = kDmiPollIterations;
52	
53	  explicit ResumeDriver(DmiBus& bus)
54	      : bus_{bus}
55	  {}
56	
57	  void resume(const hybrid_state_v1& state)
58	  {
59	    if (state.magic != HYBRID_STATE_MAGIC)
60	      throw std::runtime_error("ResumeDriver::resume: bad magic");
61	    if (state.version != HYBRID_STATE_VERSION)
62	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
63	
64	    // dmactive must transition 0->1 in its own write before any other
65	    // DMCONTROL bit is honored (RISC-V Debug Spec).
66	    bus_.write(kDmcontrol, kDmcontrolDmactive);
67	    request_halt();
68	    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");
69	
70	    // Tier-A V CSR restore (before GPRs: PB fallback uses x5 as scratch;
71	    // the GPR loop overwrites x5 afterward so state is preserved).
72	    if (state.flags & HYBRID_FLAG_V) {
73	      // mstatus: only write when VS field is non-zero (restore previous VS
74	      // mode; leave at Off when the state was Off to avoid unnecessary DM
75	      // abstract-write failures on implementations that reject mstatus).
76	      if (state.mstatus & 0x600u)
77	        write_csr_abstract_or_pb(kCsrMstatus, state.mstatus);
78	      // Tier-B: vtype+vl via vsetvl x0,x5,x6 in PB.
79	      // Direct csrrw to vtype sets vill; vl is read-only. Stage operands in
80	      // scratch GPRs x5(vl) and x6(vtype) then let vsetvl set both atomically.
81	      // x5/x6 are overwritten by the GPR loop below, so no leakage.
82	      write_64bit_register(regno_gpr(5), state.vl);
83	      write_64bit_register(regno_gpr(6), state.vtype);
84	      const std::array<uint32_t, 1> pb_vsetvl = { encode_vsetvl(0, 5, 6) };
85	      exec_progbuf(bus_, std::span<const uint32_t>{pb_vsetvl});
86	      // vstart must come AFTER vsetvl: vsetvl resets vstart to 0.
87	      write_csr_abstract_or_pb(kCsrVstart, state.vstart);
88	      write_csr_abstract_or_pb(kCsrVxsat,  state.vxsat);
89	      write_csr_abstract_or_pb(kCsrVxrm,   state.vxrm);
90	      write_csr_abstract_or_pb(kCsrVcsr,   state.vcsr);
91	    }
92	
93	    // GPRs + DPC (after V CSRs so PB scratch x5 is safe to overwrite).
94	    for (uint16_t i = 1; i < 32; ++i)
95	      write_64bit_register(regno_gpr(i), state.gpr[i]);
96	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
97	
98	    write_csr_tolerant(kCsrMtvec, state.mtvec);
99	
100	    clear_cmderr_if_set();
101	    request_resume();
102	    poll_until_set(bus_, kDmstatus, kDmstatusAllresumeack,
103	                   "ResumeDriver resume");
104	  }
105	
106	private:
107	  void request_halt()
108	  {
109	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolHaltreq);
110	  }
111	
112	  void request_resume()
113	  {
114	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolResumereq);
115	  }
116	
117	  void write_64bit_register(uint16_t regno, uint64_t value)
118	  {
119	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
120	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
121	    bus_.write(kCommand,
122	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
123	    poll_until_clear(bus_, kAbstractcs, kAbstractcsBusy,
124	                     "ResumeDriver write_register");
125	  }
126	
127	  // Abstract-first CSR write with Program Buffer fallback.
128	  // Tries an abstract register write; if the DM signals cmderr, clears it,
129	  // stages the value in scratch_gpr via abstract GPR write, then executes a
130	  // one-instruction PB (`csrrw x0, csr, scratch_gpr`).  scratch_gpr defaults
131	  // to x5 (t0) which the GPR restore loop overwrites later.
132	  void write_csr_abstract_or_pb(uint16_t csr, uint64_t value,
133	                                 uint8_t scratch_gpr = 5)
134	  {
135	    write_64bit_register(regno_csr(csr), value);
136	    if ((bus_.read(kAbstractcs) & kAbstractcsCmderrMask) == 0u) return;
137	    bus_.write(kAbstractcs, kAbstractcsCmderrMask);  // W1C: clear sticky error
138	    write_64bit_register(regno_gpr(scratch_gpr), value);
139	    const std::array<uint32_t, 1> pb = { encode_csrrw(0, csr, scratch_gpr) };
140	    exec_progbuf(bus_, std::span<const uint32_t>{pb});
141	  }
142	
143	  // Write a CSR-addressable register and clear any cmderr the DM raised.
144	  // Used for CSRs whose abstract-access support may be implementation
145	  // dependent; a missing CSR mirrors as a no-op rather than blocking the
146	  // remaining writes.
147	  void write_csr_tolerant(uint16_t csr, uint64_t value)
148	  {
149	    write_64bit_register(regno_csr(csr), value);
150	    clear_cmderr_if_set();
151	  }
152	
153	  // abstractcs.cmderr is sticky per the Debug Spec - a subsequent command
154	  // is rejected until the bits are W1C-cleared. We tolerate per-register
155	  // failures (e.g. unimplemented FPR/CSR Abstract access) by clearing the
156	  // error before resuming so the hart isn't left in a stuck state.
157	  void clear_cmderr_if_set()
158	  {
159	    const auto status = bus_.read(kAbstractcs);
160	    if ((status & kAbstractcsCmderrMask) != 0u)
161	      bus_.write(kAbstractcs, kAbstractcsCmderrMask);
162	  }
163	
164	  DmiBus& bus_;
165	};
166	
167	}  // namespace hybrid
