156	    // resume PC is restored via gdbstub P32 below, so the ELF entry
157	    // point is irrelevant. Tier-1 (no shared mmap) still needs -kernel
158	    // to populate QEMU 2's private RAM.
159	    if (shared_mem_path.empty()) {
160	      argv.push_back("-kernel");
161	      argv.push_back(elf.c_str());
162	    }
163	    argv.push_back("-gdb");
164	    argv.push_back(gdb_arg.c_str());
165	    argv.push_back("-S");
