343	                                      const hybrid_state_v1& state,
344	                                      pid_t child_pid = -1)
345	{
346	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
347	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
348	                                          child_pid);
349	  spdlog::info("hybrid handback: connected, discovering register map");
350	  gdbstub::Session sess{fd};
351	
352	  const auto reg_map = detail::discover_reg_map(sess);
353	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
354	               reg_map.size());
